const fn default_max_iterations() -> u32 {
    25
}

const fn default_timeout_seconds() -> u64 {
    60
}

const fn default_cli_wall_clock_timeout_seconds() -> u64 {
    300
}

const fn default_groundhog_attempt_budget() -> u32 {
    3
}

pub fn load_activity_asset(yaml: &str) -> Result<ActivityAsset, AssetLoadError> {
    let header = SchemaHeader::parse_yaml(yaml).map_err(AssetLoadError::HeaderParse)?;
    match header.schema_version {
        1 => Err(AssetLoadError::RetiredVersion(1)),
        2 => {
            let res: V2EnvelopeYaml<ActivityV2> =
                serde_yaml::from_str(yaml).map_err(AssetLoadError::Parse)?;
            require_kind(&res.kind, ResourceKind::Activity)?;
            Ok(ActivityAsset {
                name: res.metadata.name,
                spec: res.spec,
            })
        }
        other => Err(AssetLoadError::UnsupportedVersion(other)),
    }
}

pub fn load_job_asset(yaml: &str) -> Result<JobAsset, AssetLoadError> {
    let header = SchemaHeader::parse_yaml(yaml).map_err(AssetLoadError::HeaderParse)?;
    match header.schema_version {
        1 => Err(AssetLoadError::RetiredVersion(1)),
        2 => {
            let res: V2EnvelopeYaml<JobV2> =
                serde_yaml::from_str(yaml).map_err(AssetLoadError::Parse)?;
            require_kind(&res.kind, ResourceKind::Job)?;
            Ok(JobAsset {
                name: res.metadata.name,
                spec: res.spec,
            })
        }
        other => Err(AssetLoadError::UnsupportedVersion(other)),
    }
}

fn require_kind(actual: &ResourceKind, expected: ResourceKind) -> Result<(), AssetLoadError> {
    if actual == &expected {
        Ok(())
    } else {
        Err(AssetLoadError::KindMismatch {
            expected: expected.to_string(),
            actual: actual.to_string(),
        })
    }
}

pub fn resolve_activity_backends(activity: &mut ActivityV2, resolved: Backend) {
    if let ActivityV2Spec::AgentLoop(spec) = &mut activity.spec
        && spec.backend == Backend::Auto
    {
        spec.backend = resolved;
    }
}

pub fn resolve_job_backends(job: &mut JobV2, resolved: Backend) {
    for step in &mut job.steps {
        resolve_step_backends(step, resolved);
    }
}

fn resolve_step_backends(step: &mut JobV2Step, resolved: Backend) {
    match &mut step.body {
        JobV2StepBody::Target(target) => {
            if let ActivityV2Spec::AgentLoop(spec) = &mut target.spec
                && spec.backend == Backend::Auto
            {
                spec.backend = resolved;
            }
        }
        JobV2StepBody::TargetRef(_) => {
            // A surviving TargetRef means `resolve_job_target_refs` wasn't
            // run first. Leave it alone here; the dispatcher surfaces the
            // structural error.
        }
        JobV2StepBody::Parallel { parallel } => {
            for branch in &mut parallel.branches {
                resolve_step_backends(branch, resolved);
            }
        }
        JobV2StepBody::FanOut { fan_out, .. } => {
            resolve_step_backends(&mut fan_out.worker, resolved);
        }
        JobV2StepBody::Loop { loop_ } => {
            for nested in &mut loop_.steps {
                resolve_step_backends(nested, resolved);
            }
        }
    }
}

pub fn validate_job_loop_session_backends(
    job: &JobV2,
    asset_path: &str,
) -> Result<(), BackendConstraintError> {
    for step in &job.steps {
        validate_step(step, asset_path, false)?;
    }
    Ok(())
}

fn validate_step(
    step: &JobV2Step,
    asset_path: &str,
    inside_loop: bool,
) -> Result<(), BackendConstraintError> {
    match &step.body {
        JobV2StepBody::Target(target) => {
            if inside_loop
                && let (Some(session), ActivityV2Spec::AgentLoop(spec)) =
                    (&target.session, &target.spec)
                && spec.backend == Backend::Cli
            {
                let feature = HttpOnlyFeature::CrossIterationSession;
                return Err(BackendConstraintError::LoopSessionOnCli {
                    asset_path: asset_path.to_string(),
                    step_id: step.id.clone(),
                    session_name: session.clone(),
                    item_number: feature.item_number(),
                    feature_desc: feature.description(),
                });
            }
            Ok(())
        }
        JobV2StepBody::TargetRef(_) => {
            // See `resolve_step_backends` — a surviving ref is structural
            // breakage, not a §3.2 concern. Skip silently; the dispatcher's
            // `UnresolvedTargetRef` surfaces it.
            Ok(())
        }
        JobV2StepBody::Parallel { parallel } => {
            for branch in &parallel.branches {
                validate_step(branch, asset_path, inside_loop)?;
            }
            Ok(())
        }
        JobV2StepBody::FanOut { fan_out, .. } => {
            validate_step(&fan_out.worker, asset_path, inside_loop)
        }
        JobV2StepBody::Loop { loop_ } => validate_loop_block(loop_, asset_path),
    }
}

fn validate_loop_block(block: &LoopBlock, asset_path: &str) -> Result<(), BackendConstraintError> {
    for step in &block.steps {
        validate_step(step, asset_path, true)?;
    }
    Ok(())
}

fn walk_dir(
    dir: &Path,
    cb: &mut dyn FnMut(&Path) -> Result<(), CatalogError>,
) -> Result<(), CatalogError> {
    let iter = std::fs::read_dir(dir).map_err(|source| CatalogError::ReadDir {
        path: dir.to_path_buf(),
        source,
    })?;
    for entry in iter {
        let entry = entry.map_err(|source| CatalogError::ReadDir {
            path: dir.to_path_buf(),
            source,
        })?;
        let path = entry.path();
        if path.is_dir() {
            walk_dir(&path, cb)?;
            continue;
        }
        let is_yaml = path
            .extension()
            .and_then(|e| e.to_str())
            .is_some_and(|e| e == "yaml" || e == "yml");
        if is_yaml {
            cb(&path)?;
        }
    }
    Ok(())
}

pub fn resolve_job_target_refs(
    job: &mut JobV2,
    catalog: &V2ActivityCatalog,
) -> Result<(), ResolveError> {
    for step in &mut job.steps {
        resolve_step(step, catalog)?;
    }
    Ok(())
}

fn resolve_step(step: &mut JobV2Step, catalog: &V2ActivityCatalog) -> Result<(), ResolveError> {
    match &mut step.body {
        JobV2StepBody::Target(_) => Ok(()),
        JobV2StepBody::TargetRef(_) => {
            // Swap the body out so we can own the ref without cloning; the
            // replacement is a throwaway `Target` that we immediately
            // overwrite with the resolved one.
            let old = std::mem::replace(
                &mut step.body,
                JobV2StepBody::TargetRef(TargetRef {
                    target: String::new(),
                    default_input: None,
                    timeout_seconds: 0,
                    session: None,
                }),
            );
            let JobV2StepBody::TargetRef(r) = old else {
                unreachable!("checked above");
            };
            let resolved = resolve_ref(&step.id, r, catalog)?;
            step.body = JobV2StepBody::Target(resolved);
            Ok(())
        }
        JobV2StepBody::Parallel { parallel } => {
            for branch in &mut parallel.branches {
                resolve_step(branch, catalog)?;
            }
            Ok(())
        }
        JobV2StepBody::FanOut { fan_out, .. } => resolve_step(&mut fan_out.worker, catalog),
        JobV2StepBody::Loop { loop_ } => resolve_loop(loop_, catalog),
    }
}

fn resolve_loop(block: &mut LoopBlock, catalog: &V2ActivityCatalog) -> Result<(), ResolveError> {
    for step in &mut block.steps {
        resolve_step(step, catalog)?;
    }
    Ok(())
}

fn resolve_ref(
    step_id: &str,
    r: TargetRef,
    catalog: &V2ActivityCatalog,
) -> Result<TargetStep, ResolveError> {
    let name =
        r.target
            .strip_prefix(ACTIVITY_REF_PREFIX)
            .ok_or_else(|| ResolveError::UnknownRefKind {
                step_id: step_id.to_string(),
                target: r.target.clone(),
            })?;
    let activity = catalog
        .get(name)
        .ok_or_else(|| ResolveError::ActivityNotInCatalog {
            step_id: step_id.to_string(),
            name: name.to_string(),
        })?;
    Ok(TargetStep {
        spec: activity.spec.clone(),
        fs_profile: activity.fs_profile.clone(),
        default_input: r.default_input,
        timeout_seconds: r.timeout_seconds,
        session: r.session,
    })
}

