pub fn validate_tool_allowlist(allowlist: &[String]) -> Result<(), ToolAllowlistError> {
    for entry in allowlist {
        if entry.is_empty() {
            return Err(ToolAllowlistError::EmptyName);
        }
        if let Some(prefix) = wildcard_prefix(entry)
            && !V2_TOOL_WILDCARD_ROOTS.iter().any(|root| *root == prefix)
        {
            return Err(ToolAllowlistError::WildcardRootNotPermitted(entry.clone()));
        }
    }
    Ok(())
}

pub fn tool_allowed(tool_name: &str, allowlist: &[String]) -> bool {
    for entry in allowlist {
        if entry == tool_name {
            return true;
        }
        if let Some(prefix) = wildcard_prefix(entry)
            && tool_name.starts_with(&prefix)
        {
            return true;
        }
    }
    false
}

fn wildcard_prefix(entry: &str) -> Option<String> {
    entry.strip_suffix('*').map(|s| s.to_string())
}

pub fn normalize_attribution_label(label: &str, model_hint: Option<&str>) -> String {
    let trimmed = label.trim();
    if trimmed.is_empty() {
        return String::new();
    }

    if let Some((family, model)) = trimmed.rsplit_once(" / ") {
        let family = family.trim();
        let model = model.trim();
        let is_known_family = family.eq_ignore_ascii_case("agent")
            || all_agent_families()
                .iter()
                .any(|known| family.eq_ignore_ascii_case(known));
        if is_known_family && !model.is_empty() {
            return model.to_string();
        }
    }

    if let Some(model_hint) = model_hint.map(str::trim).filter(|value| !value.is_empty()) {
        let family = agent_family_from_cli(trimmed);
        let is_known_family = all_agent_families()
            .iter()
            .any(|known| family == *known && trimmed.eq_ignore_ascii_case(known));
        if trimmed.eq_ignore_ascii_case("agent") || is_known_family {
            return model_hint.to_string();
        }
    }

    trimmed.to_string()
}

pub fn normalize_optional_attribution_label(
    label: Option<&str>,
    model_hint: Option<&str>,
) -> Option<String> {
    label
        .map(|value| normalize_attribution_label(value, model_hint))
        .filter(|value| !value.is_empty())
}

pub const fn all_agent_families() -> [&'static str; 3] {
    ["codex", "claude", "gemini"]
}

pub fn infer_agent_family_from_model(model: &str) -> Option<String> {
    let model = model.trim().to_ascii_lowercase();
    if model.is_empty() {
        return None;
    }

    if model.starts_with("gpt-") || model.starts_with("o1") || model.starts_with("o3") {
        return Some("codex".to_string());
    }
    if model.starts_with("claude-") || model.starts_with("opus") || model.starts_with("sonnet") {
        return Some("claude".to_string());
    }
    if model.starts_with("gemini-") {
        return Some("gemini".to_string());
    }

    None
}

pub fn resolve_agent_model_pair(agent_cli: &str) -> Option<AgentModelPair> {
    resolve_agent_model_pair_or(agent_cli, None)
}

pub fn resolve_agent_model_pair_or(
    agent_cli: &str,
    config_override: Option<&AgentModelPair>,
) -> Option<AgentModelPair> {
    if let Some(override_pair) = config_override {
        return Some(override_pair.clone());
    }

    let family = agent_family_from_cli(agent_cli);
    match family.as_str() {
        "codex" => Some(AgentModelPair::new("gpt-5.4", "gpt-5.4-mini")),
        "claude" => Some(AgentModelPair::new("opus-4.6", "sonnet-4.6")),
        "gemini" => Some(AgentModelPair::new(
            "gemini-3.1-pro-preview",
            "gemini-3-flash-preview",
        )),
        _ => None,
    }
}

