fn reject_explicit_global_deny(
    policy_name: &str,
    profile_name: &str,
    section: &str,
    rule: &str,
    deny_rules: &[String],
    deny_label: &str,
) -> Result<(), OrbitError> {
    if deny_rules.iter().any(|deny_rule| deny_rule == rule) {
        return Err(OrbitError::InvalidInput(format!(
            "policy `{}` fsProfile `{}` {} rule `{}` duplicates global {} entry",
            policy_name, profile_name, section, rule, deny_label
        )));
    }
    Ok(())
}

fn rule_covers_path_rule(read_rule: &str, path_rule: &str) -> bool {
    if read_rule == path_rule || read_rule == "**" {
        return true;
    }

    if let Some(prefix) = read_rule.strip_suffix("/**") {
        if prefix.is_empty() {
            return true;
        }

        if path_rule == prefix || path_rule.starts_with(&format!("{prefix}/")) {
            return true;
        }

        if let Some(path_prefix) = path_rule.strip_suffix("/**") {
            return path_prefix == prefix || path_prefix.starts_with(&format!("{prefix}/"));
        }
    }

    false
}

fn positive_rules(rules: &[String]) -> impl Iterator<Item = &str> {
    rules
        .iter()
        .map(String::as_str)
        .filter(|rule| !rule.starts_with('!'))
}

fn normalize_rule_set(rules: &[String], label: &str) -> Result<Vec<String>, OrbitError> {
    rules
        .iter()
        .map(|rule| normalize_rule(rule, label))
        .collect()
}

fn normalize_rule(rule: &str, label: &str) -> Result<String, OrbitError> {
    let trimmed = rule.trim();
    if trimmed.is_empty() {
        return Err(OrbitError::InvalidInput(format!(
            "{label} contains an empty path rule"
        )));
    }

    let (negated, body) = split_rule(trimmed);
    let mut normalized = body.replace('\\', "/");
    while let Some(stripped) = normalized.strip_prefix("./") {
        normalized = stripped.to_string();
    }
    if normalized.is_empty() {
        normalized = ".".to_string();
    }

    if normalized == "~"
        || normalized.starts_with("~/")
        || normalized.starts_with("../")
        || normalized == ".."
    {
        return Err(OrbitError::InvalidInput(format!(
            "{label} rule `{trimmed}` must stay inside the workspace root"
        )));
    }

    let path = Path::new(&normalized);
    if path.is_absolute() {
        return Err(OrbitError::InvalidInput(format!(
            "{label} rule `{trimmed}` must stay inside the workspace root"
        )));
    }

    for component in path.components() {
        match component {
            Component::CurDir | Component::Normal(_) => {}
            Component::ParentDir | Component::RootDir | Component::Prefix(_) => {
                return Err(OrbitError::InvalidInput(format!(
                    "{label} rule `{trimmed}` must stay inside the workspace root"
                )));
            }
        }
    }

    compile_rule_regex(&normalized).map_err(|error| {
        OrbitError::InvalidInput(format!(
            "{label} rule `{trimmed}` is not a valid filesystem glob: {error}"
        ))
    })?;

    Ok(if negated {
        negate_rule(normalized)
    } else {
        normalized
    })
}

fn normalize_path(path: &str) -> Result<String, OrbitError> {
    let trimmed = path.trim();
    if trimmed.is_empty() {
        return Err(OrbitError::InvalidInput(
            "filesystem path must not be empty".to_string(),
        ));
    }

    let mut normalized = trimmed.replace('\\', "/");
    while let Some(stripped) = normalized.strip_prefix("./") {
        normalized = stripped.to_string();
    }
    if normalized == "." {
        normalized.clear();
    }
    if normalized.starts_with('/') || normalized == "~" || normalized.starts_with("~/") {
        return Err(OrbitError::InvalidInput(format!(
            "filesystem path `{path}` must stay inside the workspace root"
        )));
    }
    Ok(normalized)
}

fn split_rule(rule: &str) -> (bool, &str) {
    rule.strip_prefix('!')
        .map(|rest| (true, rest))
        .unwrap_or((false, rule))
}

fn negate_rule(rule: String) -> String {
    format!("!{rule}")
}

fn rule_matches_path(rule: &str, path: &str) -> Result<bool, OrbitError> {
    let regex = compile_rule_regex(rule).map_err(|error| {
        OrbitError::InvalidInput(format!("invalid filesystem glob `{rule}`: {error}"))
    })?;
    Ok(regex.is_match(path))
}

fn compile_rule_regex(rule: &str) -> Result<Regex, regex::Error> {
    if rule == "." {
        return Regex::new(r"^$");
    }

    if let Some(prefix) = rule.strip_suffix("/**") {
        if prefix.is_empty() {
            return Regex::new(r"^.*$");
        }
        let escaped = regex::escape(prefix);
        return Regex::new(&format!("^{escaped}(?:/.*)?$"));
    }

    let chars: Vec<char> = rule.chars().collect();
    let mut index = 0usize;
    let mut pattern = String::from("^");
    while index < chars.len() {
        if chars[index] == '*' {
            if index + 2 < chars.len() && chars[index + 1] == '*' && chars[index + 2] == '/' {
                pattern.push_str("(?:.*/)?");
                index += 3;
                continue;
            }
            if index + 1 < chars.len() && chars[index + 1] == '*' {
                pattern.push_str(".*");
                index += 2;
                continue;
            }
            pattern.push_str("[^/]*");
            index += 1;
            continue;
        }

        if chars[index] == '?' {
            pattern.push_str("[^/]");
            index += 1;
            continue;
        }

        pattern.push_str(&regex::escape(&chars[index].to_string()));
        index += 1;
    }
    pattern.push('$');
    Regex::new(&pattern)
}

pub fn parse_policy_resource(yaml: &str, label: &str) -> Result<PolicyResource, OrbitError> {
    let header: ResourceHeader = serde_yaml::from_str(yaml)
        .map_err(|error| OrbitError::InvalidInput(format!("failed to parse {label}: {error}")))?;

    if header.kind != ResourceKind::Policy {
        return Err(OrbitError::InvalidInput(format!(
            "failed to parse {label}: expected kind Policy, found {}",
            header.kind
        )));
    }

    if header.schema_version == 1 {
        return Err(OrbitError::InvalidInput(format!(
            "failed to parse {label}: policy schemaVersion 1 is no longer supported; migrate to schemaVersion 2 with `spec.denyRead`, `spec.denyModify`, and `spec.fsProfiles`"
        )));
    }

    if header.schema_version != POLICY_RESOURCE_SCHEMA_VERSION {
        return Err(OrbitError::InvalidInput(format!(
            "failed to parse {label}: unsupported policy schemaVersion {}",
            header.schema_version
        )));
    }

    serde_yaml::from_str(yaml)
        .map_err(|error| OrbitError::InvalidInput(format!("failed to parse {label}: {error}")))
}

fn merge_pipeline_patch(pipeline: &mut Value, patch: &Value) {
    if let (Some(pipeline_map), Some(patch_map)) = (pipeline.as_object_mut(), patch.as_object()) {
        for (key, value) in patch_map {
            pipeline_map.insert(key.clone(), value.clone());
        }
    }
}

pub fn prune_missing_context_files(
    workspace_root: &std::path::Path,
    candidates: Vec<String>,
) -> (Vec<String>, Vec<String>) {
    let mut kept = Vec::with_capacity(candidates.len());
    let mut dropped = Vec::new();
    for entry in candidates {
        let trimmed = entry.trim();
        if trimmed.is_empty() {
            continue;
        }
        if exists_in_workspace(trimmed, workspace_root) {
            kept.push(trimmed.to_string());
        } else {
            dropped.push(trimmed.to_string());
        }
    }
    (kept, dropped)
}

pub fn normalize_task_dependencies(
    raw_dependencies: Vec<String>,
) -> Result<Vec<OrbitId>, OrbitError> {
    let mut normalized = Vec::with_capacity(raw_dependencies.len());
    let mut seen = BTreeSet::new();
    for raw in raw_dependencies {
        let dependency = raw.trim();
        if dependency.is_empty() {
            return Err(OrbitError::InvalidInput(
                "task dependencies must not contain empty IDs".to_string(),
            ));
        }
        if seen.insert(dependency.to_string()) {
            normalized.push(dependency.to_string());
        }
    }
    Ok(normalized)
}

pub fn build_task_status_index(tasks: &[Task]) -> BTreeMap<OrbitId, TaskStatus> {
    tasks
        .iter()
        .map(|task| (task.id.clone(), task.status))
        .collect::<BTreeMap<_, _>>()
}

pub fn resolve_task_dependencies(
    task: &Task,
    status_by_id: &BTreeMap<OrbitId, TaskStatus>,
) -> Vec<ResolvedTaskDependency> {
    task.dependencies
        .iter()
        .map(|dependency_id| ResolvedTaskDependency {
            id: dependency_id.clone(),
            status: status_by_id
                .get(dependency_id)
                .map(|status| status.to_string())
                .unwrap_or_else(|| "missing".to_string()),
        })
        .collect()
}

pub fn task_dependencies_ready(task: &Task, status_by_id: &BTreeMap<OrbitId, TaskStatus>) -> bool {
    task.dependencies.iter().all(|dependency_id| {
        status_by_id
            .get(dependency_id)
            .is_some_and(|status| status.satisfies_dependency())
    })
}

pub fn unmet_task_dependencies(
    task: &Task,
    status_by_id: &BTreeMap<OrbitId, TaskStatus>,
) -> Vec<ResolvedTaskDependency> {
    resolve_task_dependencies(task, status_by_id)
        .into_iter()
        .filter(|dependency| {
            status_by_id
                .get(&dependency.id)
                .is_none_or(|status| !status.satisfies_dependency())
        })
        .collect()
}

pub fn validate_task_dependencies(
    tasks: &[Task],
    current_task_id: Option<&str>,
    dependencies: &[OrbitId],
) -> Result<(), OrbitError> {
    let task_ids = tasks
        .iter()
        .map(|task| task.id.clone())
        .collect::<BTreeSet<_>>();
    for dependency in dependencies {
        if !task_ids.contains(dependency) {
            return Err(OrbitError::InvalidInput(format!(
                "task dependency '{dependency}' does not resolve in this workspace"
            )));
        }
    }

    let Some(current_task_id) = current_task_id else {
        return Ok(());
    };

    if dependencies
        .iter()
        .any(|dependency| dependency == current_task_id)
    {
        return Err(OrbitError::InvalidInput(format!(
            "task '{current_task_id}' cannot declare a self-dependency (self-reference)"
        )));
    }

    let mut adjacency = tasks
        .iter()
        .map(|task| (task.id.clone(), task.dependencies.clone()))
        .collect::<BTreeMap<_, _>>();
    adjacency.insert(current_task_id.to_string(), dependencies.to_vec());

    for dependency in dependencies {
        let mut visiting = BTreeSet::new();
        let mut trail = Vec::new();
        if let Some(path) = find_dependency_path(
            dependency,
            current_task_id,
            &adjacency,
            &mut visiting,
            &mut trail,
        ) {
            let mut cycle = Vec::with_capacity(path.len() + 1);
            cycle.push(current_task_id.to_string());
            cycle.extend(path);
            return Err(OrbitError::InvalidInput(format!(
                "task dependency cycle detected: {}",
                cycle.join(" -> ")
            )));
        }
    }

    Ok(())
}

fn find_dependency_path(
    current: &str,
    target: &str,
    adjacency: &BTreeMap<OrbitId, Vec<OrbitId>>,
    visiting: &mut BTreeSet<OrbitId>,
    trail: &mut Vec<OrbitId>,
) -> Option<Vec<OrbitId>> {
    if !visiting.insert(current.to_string()) {
        return None;
    }

    trail.push(current.to_string());
    if current == target {
        return Some(trail.clone());
    }

    if let Some(next_dependencies) = adjacency.get(current) {
        for next in next_dependencies {
            if let Some(path) = find_dependency_path(next, target, adjacency, visiting, trail) {
                return Some(path);
            }
        }
    }

    trail.pop();
    visiting.remove(current);
    None
}

pub fn parse_task_plan(raw: &str, label: &str) -> Result<TaskPlan, OrbitError> {
    let trimmed = raw.trim();
    if trimmed.is_empty() || !looks_like_structured_task_plan(trimmed) {
        return Ok(TaskPlan::default());
    }

    serde_yaml::from_str::<TaskPlan>(trimmed)
        .map_err(|error| OrbitError::InvalidInput(format!("failed to parse {label}: {error}")))
}

fn require_string(value: Option<String>, field: &str, context: &str) -> Result<String, String> {
    let value = value.ok_or_else(|| format!("{context} missing required field '{field}'"))?;
    if value.trim().is_empty() {
        return Err(format!("{context} requires non-empty field '{field}'"));
    }
    Ok(value)
}

fn looks_like_structured_task_plan(raw: &str) -> bool {
    let Some(line) = raw.lines().map(str::trim_start).find(|line| {
        let trimmed = line.trim();
        !trimmed.is_empty() && !trimmed.starts_with('#')
    }) else {
        return false;
    };

    if line.starts_with("---") {
        return true;
    }

    let Some((key, _)) = line.split_once(':') else {
        return false;
    };
    is_simple_yaml_key(key)
}

fn is_simple_yaml_key(candidate: &str) -> bool {
    let trimmed = candidate.trim().trim_matches(|ch| ch == '"' || ch == '\'');
    !trimmed.is_empty()
        && trimmed
            .chars()
            .all(|ch| ch.is_ascii_alphanumeric() || ch == '_' || ch == '-')
}

pub fn required_string(
    input: &Value,
    keys: &[&str],
    canonical: &str,
) -> Result<String, OrbitError> {
    for key in keys {
        if let Some(value) = input.get(*key) {
            let raw = value
                .as_str()
                .ok_or_else(|| OrbitError::InvalidInput(format!("`{key}` must be a string")))?;
            let trimmed = raw.trim();
            if trimmed.is_empty() {
                return Err(OrbitError::InvalidInput(format!(
                    "`{key}` must not be empty"
                )));
            }
            return Ok(trimmed.to_string());
        }
    }
    Err(OrbitError::InvalidInput(format!("missing `{canonical}`")))
}

pub fn optional_string(input: &Value, key: &str) -> Result<Option<String>, OrbitError> {
    match input.get(key) {
        None | Some(Value::Null) => Ok(None),
        Some(value) => {
            let raw = value
                .as_str()
                .ok_or_else(|| OrbitError::InvalidInput(format!("`{key}` must be a string")))?;
            let trimmed = raw.trim();
            if trimmed.is_empty() {
                return Err(OrbitError::InvalidInput(format!(
                    "`{key}` must not be empty"
                )));
            }
            Ok(Some(trimmed.to_string()))
        }
    }
}

pub fn optional_raw_string(input: &Value, key: &str) -> Result<Option<String>, OrbitError> {
    match input.get(key) {
        None | Some(Value::Null) => Ok(None),
        Some(value) => {
            let raw = value
                .as_str()
                .ok_or_else(|| OrbitError::InvalidInput(format!("`{key}` must be a string")))?;
            Ok(Some(raw.to_string()))
        }
    }
}

pub fn optional_string_alias(input: &Value, keys: &[&str]) -> Result<Option<String>, OrbitError> {
    for key in keys {
        if let Some(value) = input.get(*key) {
            let raw = value
                .as_str()
                .ok_or_else(|| OrbitError::InvalidInput(format!("`{key}` must be a string")))?;
            let trimmed = raw.trim();
            if trimmed.is_empty() {
                return Err(OrbitError::InvalidInput(format!(
                    "`{key}` must not be empty"
                )));
            }
            return Ok(Some(trimmed.to_string()));
        }
    }
    Ok(None)
}

pub fn optional_u32_alias(input: &Value, keys: &[&str]) -> Result<Option<u32>, OrbitError> {
    for key in keys {
        if let Some(value) = input.get(*key) {
            let raw = match value {
                Value::String(value) => value.trim().to_string(),
                Value::Number(value) => value.to_string(),
                _ => {
                    return Err(OrbitError::InvalidInput(format!(
                        "`{key}` must be a string or integer"
                    )));
                }
            };
            if raw.is_empty() {
                return Err(OrbitError::InvalidInput(format!(
                    "`{key}` must not be empty"
                )));
            }
            return raw.parse::<u32>().map(Some).map_err(|error| {
                OrbitError::InvalidInput(format!("`{key}` must be an unsigned integer: {error}"))
            });
        }
    }
    Ok(None)
}

pub fn optional_string_list_alias(
    input: &Value,
    keys: &[&str],
) -> Result<Option<Vec<String>>, OrbitError> {
    for key in keys {
        if let Some(value) = input.get(*key) {
            return match value {
                Value::String(raw) => {
                    let trimmed = raw.trim();
                    if trimmed.is_empty() {
                        Err(OrbitError::InvalidInput(format!(
                            "`{key}` must not be empty"
                        )))
                    } else {
                        Ok(Some(vec![trimmed.to_string()]))
                    }
                }
                Value::Array(items) => {
                    let mut values = Vec::with_capacity(items.len());
                    for item in items {
                        let raw = item.as_str().ok_or_else(|| {
                            OrbitError::InvalidInput(format!("`{key}` entries must be strings"))
                        })?;
                        let trimmed = raw.trim();
                        if trimmed.is_empty() {
                            return Err(OrbitError::InvalidInput(format!(
                                "`{key}` entries must not be empty"
                            )));
                        }
                        values.push(trimmed.to_string());
                    }
                    Ok(Some(values))
                }
                _ => Err(OrbitError::InvalidInput(format!(
                    "`{key}` must be a string or array of strings"
                ))),
            };
        }
    }
    Ok(None)
}

pub fn optional_csv_or_string_list_alias(
    input: &Value,
    keys: &[&str],
) -> Result<Option<Vec<String>>, OrbitError> {
    optional_string_list_alias(input, keys).map(|values| {
        values.map(|items| {
            items
                .into_iter()
                .flat_map(|item| split_csv(&item))
                .collect::<Vec<_>>()
        })
    })
}

fn default_base_branch() -> String {
    "main".to_string()
}

fn default_status() -> WorkspaceStatus {
    WorkspaceStatus::Active
